    [InlineData(ItemEnum.GPG_AES_128_AES256_SHA1_PLAINTEXT , "$gpg$*1*348*1024**3*254*2*7*16*a47ef38987beab0a0b9bfe74b72822e8*65536*1f5c90d9820997db")]
    [InlineData(ItemEnum.KEEPASS1_AES_TWOFISH_KEEPASS2_AES , "$keepass$*2*60000*0*02078d460c3c837003f22ee2ba42b3ac2a9ad9e913efb61349b3f91aacd0b004*c901781373cb6806df4b4c7b427ba698440f9e9dd68101e6a198e4a95cb10098*c602f182f8b03671c944a5af357eede7*135443633e6d2b6dba314dee0a1e2b5d0c025ca5fcaf692a20d77fb62cc44f63*51b0b2d19d82c88a0d1a646151be0b68c5e3c841a7a21b4abb2e9be14f298ed1")]
    [InlineData(ItemEnum.TELEGRAM_DESKTOP_AFTER_V2114_PBKDF_HMAC_SHA1 , "$telegram$2*100000*77461dcb457ce9539f8e4235d33bd12455b4a38446e63b52ecdf2e7b65af4476*")]
    [InlineData(ItemEnum.PKCS8_PRIVATE_KEYS_PBKDF2_HMAC_SHA1_3DES_AES , "$PEM$1$4$f5662bd8383b4b40$2048$2993b585d3fb2e7b235ed13d90f637e2$1232$")]
    // [InlineData(ItemEnum.PKCS8_PRIVATE_KEYS_PBKDF2_HMAC_SHA256_3DES_AES , "$PEM$2$4$ed02960b8a10b1f1$2048$a634c482a95f23bd8fada558e1bac2cf$1232$")]  // hashes.com mismatch Possible algorithms: PKCS#8 Private Keys (PBKDF2-HMAC-SHA1 + 3DES/AES)...
    public async Task TryParse_ShouldDetectHashAndReturnEnum(ItemEnum expected, string hash)
    {
        var (ok, result) = await HashParser.TryParse(hash);

        Assert.True(ok, $"Hash should be detected: {hash}");
        Assert.Equal(expected, result);
    }

    // INVALID HASHES
    [Theory]
    [InlineData("")]
    [InlineData("5)")]  //hashes.com recognized as Base64
    [InlineData("not_a_hash")]
    [InlineData("12345")]
    [InlineData("hello world")]
    [InlineData("johndoe@example.com")]
    [InlineData("zzzzzzzzzzzzzzzzzzzzzz")]
    [InlineData("!!!@@@###")]
    public async Task TryParse_ShouldRejectInvalidHashes(string input)
    {
        var (ok, result) = await HashParser.TryParse(input);
    
        Assert.False(ok, $"Should reject non-hash input: {input}");
        Assert.Equal(ItemEnum.Null, result);
    }
}